import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

class PaymentProcessor {
  final String apiKey;

  PaymentProcessor({required this.apiKey});

  Future<void> processPayment(double amount, String currency, String paymentMethod) async {
    try {
      var url = Uri.parse('https://api.paymentgateway.com/transaction');
      var headers = {'Authorization': 'Bearer $apiKey', 'Content-Type': 'application/json'};
      var body = jsonEncode({
        'amount': amount,
        'currency': currency,
        'paymentMethod': paymentMethod
      });

      var response = await http.post(url, headers: headers, body: body);

      if (response.statusCode == 200) {
        print('Payment processed successfully');
      } else {
        throw Exception('Failed to process payment');
      }
    } catch (e) {
      print('Error processing payment: $e');
    }
  }

  Future<void> integrateMobileWallet(String walletType, String userId) async {
    try {
      var url = Uri.parse('https://api.paymentgateway.com/wallet/integrate');
      var headers = {'Authorization': 'Bearer $apiKey', 'Content-Type': 'application/json'};
      var body = jsonEncode({
        'walletType': walletType,
        'userId': userId
      });

      var response = await http.post(url, headers: headers, body: body);

      if (response.statusCode == 200) {
        print('Mobile wallet integration successful');
      } else {
        throw Exception('Failed to integrate mobile wallet');
      }
    } catch (e) {
      print('Error integrating mobile wallet: $e');
    }
  }
}

class PaymentModule extends StatefulWidget {
